// Restructure data and KEEP binary
return items.map(item => {
  const uploadFile = item.json['Upload File'];
  const fileStoreName = item.json['File Store Name'] || 'fileSearchStores/n8ndocumentsstore-f7cqp3cqctc6';

  console.log('=== DEBUG: File Store Name =', fileStoreName);

  // Get the first binary field
  const binaryKeys = Object.keys(item.binary || {});
  const firstBinaryKey = binaryKeys[0];

  const binaryData = {};
  if (firstBinaryKey) {
    binaryData.data = item.binary[firstBinaryKey];
  }

  return {
    json: {
      filename: uploadFile.filename,
      mimetype: uploadFile.mimetype,
      size: uploadFile.size,
      submittedAt: item.json.submittedAt,
      formMode: item.json.formMode,
      store_name: fileStoreName
    },
    binary: binaryData
  };
});

// Debug node to check upload result
const uploadResult = $input.item.json;
const fileData = $('Prepare File Data').item.json;

console.log('=== DEBUG: Upload Result ===');
console.log('Full response:', JSON.stringify(uploadResult, null, 2));
console.log('File name:', uploadResult.file?.name || 'NOT FOUND');
console.log('Store name:', fileData.store_name);

return {
  json: {
    debug_info: {
      upload_response: uploadResult,
      file_name_from_upload: uploadResult.file?.name || 'NOT FOUND',
      store_name: fileData.store_name,
      original_filename: fileData.filename
    }
  }
};

// Format success response
const importResult = $input.item.json;
const fileData = $('Prepare File Data').item.json;
const uploadResult = $('Upload File to Gemini').item.json;

return {
  json: {
    success: true,
    message: 'File successfully uploaded and indexed',
    details: {
      original_filename: fileData.filename,
      file_size: fileData.size,
      mime_type: fileData.mimetype,
      gemini_file_name: uploadResult.file?.name || 'Unknown',
      store_name: fileData.store_name,
      uploaded_at: fileData.submittedAt,
      import_result: importResult
    }
  }
};
